class CircularIterator:
    def __init__(self, data, n):
        self.data = data
        self.n = n
        self.index = 0
        self.count = 0

    def __iter__(self):
        return self

    def __next__(self):
        if self.count >= self.n:
            raise StopIteration

        if self.index >= len(self.data):
            self.index = 0

        item = self.data[self.index]
        self.index += 1
        self.count += 1
        return item

def circular_iterator(data, n):
    return list(CircularIterator(data, n))

if __name__ == "__main__":
    data = list(map(int, input().split()))
    n = int(input())
    result = circular_iterator(data, n)
    print(result)
